{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/record_batches.py","content":"def batch_records(
    records: list[str],
    max_items: int,
    max_bytes: int,
) -> list[list[str]]:
    """Greedily batch strings by item count and UTF-8 byte length."""
    if (
        isinstance(max_items, bool)
        or not isinstance(max_items, int)
        or max_items <= 0
        or isinstance(max_bytes, bool)
        or not isinstance(max_bytes, int)
        or max_bytes <= 0
    ):
        raise ValueError("batch limits must be positive integers")
    if isinstance(records, (str, bytes)):
        raise ValueError("records must be a non-string iterable")
    try:
        values = list(records)
    except TypeError as exc:
        raise ValueError("records must be iterable") from exc

    batches: list[list[str]] = []
    current: list[str] = []
    current_size = 0
    for record in values:
        if not isinstance(record, str):
            raise ValueError("every record must be a string")
        try:
            record_size = len(record.encode("utf-8"))
        except UnicodeEncodeError as exc:
            raise ValueError("record must be UTF-8 encodable") from exc
        if record_size > max_bytes:
            raise ValueError("record exceeds max_bytes")
        if current and (
            len(current) >= max_items
            or current_size + record_size > max_bytes
        ):
            batches.append(current)
            current = []
            current_size = 0
        current.append(record)
        current_size += record_size
    if current:
        batches.append(current)
    return batches
